$\begin{aligned}
3\sqrt{5} + \sqrt{20} &= 3\sqrt{5} + \sqrt{4 \times 5} \quad &\text{Simplify } \sqrt{20} \text{ (简化 } \sqrt{20})
\\ &= 3\sqrt{5} + 2\sqrt{5} \quad &\text{Extract square factor (提取平方因子)}
\\ &= (3+2)\sqrt{5} \quad &\text{Combine like surds (合并同类根式)}
\\ &= 5\sqrt{5}
\end{aligned}$

$\begin{aligned}
\sqrt{2}(3 + \sqrt{8}) &= \sqrt{2} \times 3 + \sqrt{2} \times \sqrt{8} \quad &\text{Distribute } \sqrt{2} \text{ (分配 } \sqrt{2})
\\ &= 3\sqrt{2} + \sqrt{16} \quad &\text{Multiply surds (根式相乘)}
\\ &= 3\sqrt{2} + 4 \quad &\text{Simplify } \sqrt{16} \text{ (简化 } \sqrt{16})
\end{aligned}$

$\begin{aligned}
2\sqrt{18} + 5\sqrt{2} - \sqrt{32} &= 2\sqrt{9 \times 2} + 5\sqrt{2} - \sqrt{16 \times 2} \quad &\text{Simplify each surd (简化每个根式)}
\\ &= 2(3\sqrt{2}) + 5\sqrt{2} - 4\sqrt{2} \quad &\text{Extract square factors (提取平方因子)}
\\ &= 6\sqrt{2} + 5\sqrt{2} - 4\sqrt{2} \quad &\text{Multiply coefficients (乘以系数)}
\\ &= (6+5-4)\sqrt{2} \quad &\text{Combine like surds (合并同类根式)}
\\ &= 7\sqrt{2}
\end{aligned}$

$\begin{aligned}
(2 + \sqrt{3})(4 - \sqrt{3}) &= 2(4) + 2(-\sqrt{3}) + \sqrt{3}(4) + \sqrt{3}(-\sqrt{3}) \quad &\text{Use FOIL method (使用FOIL方法)}
\\ &= 8 - 2\sqrt{3} + 4\sqrt{3} - 3 \quad &\text{Multiply terms (各项相乘)}
\\ &= (8-3) + (-2+4)\sqrt{3} \quad &\text{Combine rational and surd terms (合并有理项和根式项)}
\\ &= 5 + 2\sqrt{3}
\end{aligned}$

$\begin{aligned}
(4 - \sqrt{5})(4 + \sqrt{5}) &= 4^2 - (\sqrt{5})^2 \quad &\text{Using difference of squares formula (使用平方差公式)}
\\ &= 16 - 5 \quad &\text{Calculate squares (计算平方)}
\\ &= 11 \quad &\text{Result is a rational number (结果是一个有理数)}
\end{aligned}$

$\begin{aligned}
\frac{6}{\sqrt{3}} &= \frac{6}{\sqrt{3}} \times \frac{\sqrt{3}}{\sqrt{3}} \quad &\text{Multiply numerator and denominator by } \sqrt{3} \text{ (分子分母同乘以 } \sqrt{3})
\\ &= \frac{6\sqrt{3}}{3} \quad &\text{Simplify denominator (简化分母)}
\\ &= 2\sqrt{3} \quad &\text{Simplify the fraction (简化分数)}
\end{aligned}$

$\begin{aligned}
\frac{2}{3 - \sqrt{2}} &= \frac{2}{3 - \sqrt{2}} \times \frac{3 + \sqrt{2}}{3 + \sqrt{2}} \quad &\text{Multiply by the conjugate of the denominator (乘以分母的共轭根式)}
\\ &= \frac{2(3 + \sqrt{2})}{(3 - \sqrt{2})(3 + \sqrt{2})} \quad &\text{Expand numerator and denominator (展开分子和分母)}
\\ &= \frac{6 + 2\sqrt{2}}{3^2 - (\sqrt{2})^2} \quad &\text{Use difference of squares in denominator (分母使用平方差公式)}
\\ &= \frac{6 + 2\sqrt{2}}{9 - 2}
\\ &= \frac{6 + 2\sqrt{2}}{7}
\end{aligned}$
